import crypto from "node:crypto";
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
const TEST_HOME = path.join(os.tmpdir(), `bitfab-active-studio-test-${process.pid}`);
vi.mock("node:os", async (importOriginal) => {
    const actual = await importOriginal();
    return {
        ...actual,
        homedir: () => TEST_HOME,
        default: { ...actual, homedir: () => TEST_HOME },
    };
});
function expectedFilePathForCwd(cwd) {
    const hash = crypto
        .createHash("sha256")
        .update(cwd)
        .digest("hex")
        .slice(0, 16);
    return path.join(TEST_HOME, ".config", "bitfab", `active-studio-session.${hash}.json`);
}
const { writeActiveStudioSession, markActiveStudioSessionEnded, markActiveStudioSessionClosed, reactivateActiveStudioSession, readActiveStudioSession, } = await import("./activeStudioSession.js");
// Stable agent-session env vars the scope resolver honors. Cleared before each
// test so the cwd-based tests exercise the fallback deterministically (the
// suite itself runs inside an agent that sets one of these).
const AGENT_SESSION_ENV_VARS = ["CLAUDE_CODE_SESSION_ID", "CODEX_THREAD_ID"];
describe("activeStudioSession", () => {
    let savedAgentEnv = {};
    beforeEach(() => {
        fs.rmSync(TEST_HOME, { recursive: true, force: true });
        savedAgentEnv = {};
        for (const key of AGENT_SESSION_ENV_VARS) {
            savedAgentEnv[key] = process.env[key];
            delete process.env[key];
        }
    });
    afterEach(() => {
        fs.rmSync(TEST_HOME, { recursive: true, force: true });
        for (const key of AGENT_SESSION_ENV_VARS) {
            if (savedAgentEnv[key] === undefined) {
                delete process.env[key];
            }
            else {
                process.env[key] = savedAgentEnv[key];
            }
        }
        vi.restoreAllMocks();
    });
    it("writes and reads back the active session", () => {
        writeActiveStudioSession({
            sessionId: "test-session-id",
            serviceUrl: "http://localhost:3001",
        });
        const got = readActiveStudioSession();
        expect(got).not.toBeNull();
        expect(got?.sessionId).toBe("test-session-id");
        expect(got?.serviceUrl).toBe("http://localhost:3001");
        expect(got?.pid).toBe(process.pid);
        expect(typeof got?.startedAt).toBe("string");
    });
    it("returns null when no session has been written", () => {
        expect(readActiveStudioSession()).toBeNull();
    });
    it("returns a session recorded by a dead pid (browser tab may outlive the CLI)", () => {
        const file = expectedFilePathForCwd(process.cwd());
        fs.mkdirSync(path.dirname(file), { recursive: true });
        const deadPid = 9_999_999;
        fs.writeFileSync(file, JSON.stringify({
            sessionId: "stale",
            serviceUrl: "http://localhost",
            pid: deadPid,
            startedAt: new Date().toISOString(),
        }));
        const result = readActiveStudioSession();
        expect(result).not.toBeNull();
        expect(result?.sessionId).toBe("stale");
    });
    it("returns null when the file is malformed", () => {
        const file = expectedFilePathForCwd(process.cwd());
        fs.mkdirSync(path.dirname(file), { recursive: true });
        fs.writeFileSync(file, "not json");
        expect(readActiveStudioSession()).toBeNull();
    });
    it("markActiveStudioSessionEnded sets endedAt only, keeping the file", () => {
        writeActiveStudioSession({
            sessionId: "to-end",
            serviceUrl: "http://localhost",
        });
        const file = expectedFilePathForCwd(process.cwd());
        markActiveStudioSessionEnded("to-end");
        expect(fs.existsSync(file)).toBe(true);
        const got = readActiveStudioSession();
        expect(got?.sessionId).toBe("to-end");
        expect(typeof got?.endedAt).toBe("string");
        // A deliberate end does not by itself mark the window closed.
        expect(got?.closedAt).toBeUndefined();
    });
    it("markActiveStudioSessionClosed sets closedAt only, keeping the file", () => {
        writeActiveStudioSession({
            sessionId: "to-close",
            serviceUrl: "http://localhost",
        });
        const file = expectedFilePathForCwd(process.cwd());
        markActiveStudioSessionClosed("to-close");
        expect(fs.existsSync(file)).toBe(true);
        const got = readActiveStudioSession();
        expect(got?.sessionId).toBe("to-close");
        expect(typeof got?.closedAt).toBe("string");
        expect(got?.endedAt).toBeUndefined();
    });
    it("mark functions no-op when the session id differs", () => {
        writeActiveStudioSession({
            sessionId: "live-session",
            serviceUrl: "http://localhost",
        });
        // A slow old poller for a different session must not mark the current one.
        markActiveStudioSessionEnded("some-other-session");
        markActiveStudioSessionClosed("some-other-session");
        const got = readActiveStudioSession();
        expect(got?.endedAt).toBeUndefined();
        expect(got?.closedAt).toBeUndefined();
    });
    it("mark functions leave an already-stamped timestamp untouched", () => {
        writeActiveStudioSession({
            sessionId: "stamped-once",
            serviceUrl: "http://localhost",
        });
        markActiveStudioSessionClosed("stamped-once");
        const firstClosedAt = readActiveStudioSession()?.closedAt;
        expect(typeof firstClosedAt).toBe("string");
        markActiveStudioSessionClosed("stamped-once");
        expect(readActiveStudioSession()?.closedAt).toBe(firstClosedAt);
    });
    it("mark functions defer when another LIVE process owns the record", () => {
        // process.ppid is a different, alive process: a stale poller must not stamp
        // a record a newer live process re-bound to the same session id.
        const file = expectedFilePathForCwd(process.cwd());
        fs.mkdirSync(path.dirname(file), { recursive: true });
        fs.writeFileSync(file, JSON.stringify({
            sessionId: "owned-by-live-other",
            serviceUrl: "http://localhost",
            pid: process.ppid,
            startedAt: new Date().toISOString(),
        }));
        markActiveStudioSessionEnded("owned-by-live-other");
        markActiveStudioSessionClosed("owned-by-live-other");
        const got = readActiveStudioSession();
        expect(got?.endedAt).toBeUndefined();
        expect(got?.closedAt).toBeUndefined();
    });
    it("mark functions stamp when the recorded pid is dead (creator gone)", () => {
        // A dead creator pid: an external command (closeStudio) can still mark.
        const file = expectedFilePathForCwd(process.cwd());
        fs.mkdirSync(path.dirname(file), { recursive: true });
        fs.writeFileSync(file, JSON.stringify({
            sessionId: "owned-by-dead",
            serviceUrl: "http://localhost",
            pid: 9_999_999,
            startedAt: new Date().toISOString(),
        }));
        markActiveStudioSessionEnded("owned-by-dead");
        expect(typeof readActiveStudioSession()?.endedAt).toBe("string");
    });
    it("reactivateActiveStudioSession clears terminal markers when the session matches", () => {
        writeActiveStudioSession({
            sessionId: "to-reactivate",
            serviceUrl: "http://localhost",
        });
        markActiveStudioSessionEnded("to-reactivate");
        expect(readActiveStudioSession()?.endedAt).toBeDefined();
        reactivateActiveStudioSession("to-reactivate");
        const got = readActiveStudioSession();
        expect(got?.sessionId).toBe("to-reactivate");
        expect(got?.endedAt).toBeUndefined();
        expect(got?.closedAt).toBeUndefined();
    });
    it("reactivateActiveStudioSession no-ops when the session id differs", () => {
        writeActiveStudioSession({
            sessionId: "ended-session",
            serviceUrl: "http://localhost",
        });
        markActiveStudioSessionEnded("ended-session");
        reactivateActiveStudioSession("some-other-session");
        expect(readActiveStudioSession()?.endedAt).toBeDefined();
    });
    it("scopes the session file by agent session id so concurrent agents don't collide", () => {
        // Same cwd, two different agent sessions -> separate records.
        process.env.CLAUDE_CODE_SESSION_ID = "agent-a";
        writeActiveStudioSession({
            sessionId: "from-agent-a",
            serviceUrl: "http://a",
        });
        process.env.CLAUDE_CODE_SESSION_ID = "agent-b";
        writeActiveStudioSession({
            sessionId: "from-agent-b",
            serviceUrl: "http://b",
        });
        // Agent A still sees its own session; agent B's write didn't clobber it.
        process.env.CLAUDE_CODE_SESSION_ID = "agent-a";
        expect(readActiveStudioSession()?.sessionId).toBe("from-agent-a");
        process.env.CLAUDE_CODE_SESSION_ID = "agent-b";
        expect(readActiveStudioSession()?.sessionId).toBe("from-agent-b");
    });
    it("falls back to cwd scoping when no agent session id is set", () => {
        // First "worktree": write from a known cwd, then read it back.
        const cwdA = "/private/tmp/worktree-a";
        const cwdB = "/private/tmp/worktree-b";
        const originalCwd = process.cwd.bind(process);
        const cwdSpy = vi.spyOn(process, "cwd");
        cwdSpy.mockReturnValue(cwdA);
        writeActiveStudioSession({ sessionId: "from-a", serviceUrl: "http://a" });
        cwdSpy.mockReturnValue(cwdB);
        writeActiveStudioSession({ sessionId: "from-b", serviceUrl: "http://b" });
        // Worktree A still sees its own session — worktree B's write didn't
        // clobber it, because the per-cwd-hash filename keeps them separate.
        cwdSpy.mockReturnValue(cwdA);
        expect(readActiveStudioSession()?.sessionId).toBe("from-a");
        cwdSpy.mockReturnValue(cwdB);
        expect(readActiveStudioSession()?.sessionId).toBe("from-b");
        cwdSpy.mockImplementation(originalCwd);
    });
});
